I have a massive 900-line UIViewController that handles a user profile screen. It does networking directly (URLSession), formats dates and currencies, manages navigation (pushes to settings, presents image picker), and has inline UITableView data source logic. Help me refactor this into proper VIPER architecture. Here's a simplified version of the current code:

class ProfileViewController: UIViewController, UITableViewDataSource, UITableViewDelegate, UIImagePickerControllerDelegate {
    var userId: String!
    var user: User?
    var posts: [Post] = []
    var isLoading = false
    var error: String?

    override func viewDidLoad() {
        super.viewDidLoad()
        fetchProfile()
    }

    func fetchProfile() {
        isLoading = true
        tableView.reloadData()
        URLSession.shared.dataTask(with: URL(string: "https://api.example.com/users/\(userId!)")!) { [weak self] data, _, error in
            DispatchQueue.main.async {
                self?.isLoading = false
                if let data = data, let user = try? JSONDecoder().decode(User.self, from: data) {
                    self?.user = user
                    self?.title = user.name
                    self?.tableView.reloadData()
                } else {
                    self?.error = error?.localizedDescription ?? "Failed"
                    self?.tableView.reloadData()
                }
            }
        }.resume()
    }

    func tableView(_ tableView: UITableView, didSelectRowAt indexPath: IndexPath) {
        if indexPath.section == 1 {
            let vc = PostDetailViewController()
            vc.post = posts[indexPath.row]
            navigationController?.pushViewController(vc, animated: true)
        }
    }

    @objc func settingsTapped() {
        let settingsVC = SettingsViewController()
        settingsVC.user = user
        navigationController?.pushViewController(settingsVC, animated: true)
    }

    @objc func changeAvatarTapped() {
        let picker = UIImagePickerController()
        picker.delegate = self
        present(picker, animated: true)
    }
}

