protocol SettingsViewProtocol {
    func showSettings(_ viewModel: SettingsViewModel)
    func showError(_ message: String)
}

protocol SettingsInteractorOutputProtocol {
    func didFetchSettings(_ settings: Settings)
    func didFailToFetchSettings(_ error: Error)
}

class SettingsViewController: UIViewController, SettingsViewProtocol {
    var presenter: SettingsPresenter!

    override func viewDidLoad() {
        super.viewDidLoad()
        presenter.viewDidLoad()
    }

    func showSettings(_ viewModel: SettingsViewModel) { /* update UI */ }
    func showError(_ message: String) { /* show alert */ }
}

class SettingsPresenter: SettingsInteractorOutputProtocol {
    var view: SettingsViewProtocol!
    var interactor: SettingsInteractor!
    var router: SettingsRouter!

    func viewDidLoad() {
        interactor.fetchSettings()
    }

    func didFetchSettings(_ settings: Settings) {
        let vm = SettingsViewModel(settings)
        view.showSettings(vm)
    }
    func didFailToFetchSettings(_ error: Error) {
        view.showError(error.localizedDescription)
    }
}

class SettingsInteractor {
    var presenter: SettingsInteractorOutputProtocol!
    let settingsService: SettingsServiceProtocol

    init(settingsService: SettingsServiceProtocol) {
        self.settingsService = settingsService
    }

    func fetchSettings() {
        settingsService.getSettings { [weak self] result in
            switch result {
            case .success(let settings): self?.presenter.didFetchSettings(settings)
            case .failure(let error): self?.presenter.didFailToFetchSettings(error)
            }
        }
    }
}

class SettingsRouter {
    var viewController: SettingsViewController!
}
